const msg = $json.message || $json.edited_message || {};
const text = (msg.text || '').trim();
const chat_id = msg.chat?.id;
const user_id = msg.from?.id;
const username = msg.from?.username || '';

const parts = text.split(/\s+/);
const rawCmd = parts[0] || '';
const isSlashCmd = rawCmd.startsWith('/');
const cmd = rawCmd.toLowerCase().replace(/^\//, '');
const sub = (parts[1] || '').toLowerCase();
const args = parts.slice(2);

// Sanitize: remove aspas simples para prevenir SQL injection básico
const esc = (s) => String(s || '').replace(/'/g, "''").substring(0, 200);
const safeInt = (v, def=10, max=50) => Math.min(Math.max(parseInt(v) || def, 1), max);

const knownCommands = ['nicho','canal','video','status','clips','ajuda','help','start'];
const isKnownCmd = knownCommands.includes(cmd);

let result = {
  chat_id,
  user_id,
  username,
  needs_db: false,
  sql: '',
  format: '',
  reply_text: '',
  is_conversation: !isSlashCmd,
  user_message: text,
  error: null
};

// ── /ajuda | /help | /start ───────────────────────────────────────────────
if (!isSlashCmd) {
  result.is_conversation = true;
  result.format = 'conversation';
  return [{ json: result }];
}

if (['ajuda','help','start'].includes(cmd)) {
  result.reply_text = [
    '🤖 *RACC Pipeline Manager*',
    '',
    '🏷️ *Nichos:*',
    '`/nicho list` — listar todos',
    '`/nicho add <slug> <nome> [kw1,kw2]` — adicionar',
    '`/nicho enable <slug>` — ativar',
    '`/nicho disable <slug>` — desativar',
    '`/nicho keywords <slug> kw1,kw2,...` — atualizar keywords',
    '',
    '📡 *Canais:*',
    '`/canal list [nicho]` — listar canais',
    '`/canal add <channel_id> <nome> <nicho>` — adicionar canal manualmente',
    '`/canal enable <channel_id>` — ativar canal',
    '`/canal disable <channel_id>` — desativar canal',
    '',
    '🎬 *Vídeos:*',
    '`/video list [status] [limit]` — listar',
    '`/video reprocessar <video_id>` — recolocar como pendente',
    '',
    '📊 *Pipeline:*',
    '`/status` — resumo geral',
    '`/clips [nicho]` — clips prontos para publicar',
  ].join('\n');
  result.format = 'static';
  return [{ json: result }];
}

// ── /nicho ────────────────────────────────────────────────────────────────
if (cmd === 'nicho') {
  if (sub === 'list') {
    result.sql = `SELECT slug, nome, idioma, ativo,
  COALESCE(jsonb_array_length(keywords), 0) as num_keywords
FROM nichos ORDER BY ativo DESC, nome;`;
    result.format = 'nicho_list';
    result.needs_db = true;

  } else if (sub === 'add') {
    const slug = esc(args[0]), nome = esc(args[1]);
    const kws = args[2] ? args[2].split(',').map(k => esc(k.trim())) : [];
    if (!slug || !nome) {
      result.reply_text = '❌ Uso: `/nicho add <slug> <nome> [kw1,kw2,...]`';
      result.format = 'static';
    } else {
      const kwJson = JSON.stringify(kws).replace(/'/g, "''");
      result.sql = `INSERT INTO nichos (slug, nome, keywords, idioma, ativo)
VALUES ('${slug}', '${nome}', '${kwJson}'::jsonb, 'pt-BR', true)
ON CONFLICT (slug) DO NOTHING
RETURNING id, slug, nome, ativo;`;
      result.format = 'nicho_upsert';
      result.needs_db = true;
    }

  } else if (sub === 'enable') {
    const slug = esc(args[0]);
    if (!slug) { result.reply_text = '❌ Uso: `/nicho enable <slug>`'; result.format = 'static'; }
    else {
      result.sql = `UPDATE nichos SET ativo=true, updated_at=NOW() WHERE slug='${slug}' RETURNING slug, nome, ativo;`;
      result.format = 'nicho_upsert'; result.needs_db = true;
    }

  } else if (sub === 'disable') {
    const slug = esc(args[0]);
    if (!slug) { result.reply_text = '❌ Uso: `/nicho disable <slug>`'; result.format = 'static'; }
    else {
      result.sql = `UPDATE nichos SET ativo=false, updated_at=NOW() WHERE slug='${slug}' RETURNING slug, nome, ativo;`;
      result.format = 'nicho_upsert'; result.needs_db = true;
    }

  } else if (sub === 'keywords') {
    const slug = esc(args[0]);
    const kws = args[1] ? args[1].split(',').map(k => esc(k.trim())) : [];
    if (!slug || !kws.length) { result.reply_text = '❌ Uso: `/nicho keywords <slug> kw1,kw2,...`'; result.format = 'static'; }
    else {
      const kwJson = JSON.stringify(kws).replace(/'/g, "''");
      result.sql = `UPDATE nichos SET keywords='${kwJson}'::jsonb, updated_at=NOW() WHERE slug='${slug}' RETURNING slug, nome;`;
      result.format = 'nicho_upsert'; result.needs_db = true;
    }

  } else {
    result.reply_text = '❓ Uso: `/nicho list|add|enable|disable|keywords`';
    result.format = 'static';
  }

// ── /canal ────────────────────────────────────────────────────────────────
} else if (cmd === 'canal') {
  if (sub === 'list') {
    const nicho = args[0] ? `AND nicho_alvo='${esc(args[0])}'` : '';
    result.sql = `SELECT canal_id, nome_canal, nicho_alvo, inscritos,
  ROUND(score::numeric,2) as score, ativo
FROM canais_descobertos
WHERE true ${nicho}
ORDER BY nicho_alvo, score DESC LIMIT 30;`;
    result.format = 'canal_list'; result.needs_db = true;

  } else if (sub === 'add') {
    const cid = esc(args[0]), nome = esc(args[1]), nicho = esc(args[2]);
    if (!cid || !nome || !nicho) { result.reply_text = '❌ Uso: `/canal add <channel_id> <nome> <nicho>`'; result.format = 'static'; }
    else {
      result.sql = `INSERT INTO canais_descobertos
  (plataforma, canal_id, nome_canal, nicho_alvo, score, ativo, data_ultima_analise)
VALUES ('youtube', '${cid}', '${nome}', '${nicho}', 0.70, true, NOW())
ON CONFLICT (canal_id) DO NOTHING
RETURNING canal_id, nome_canal, nicho_alvo, ativo;`;
      result.format = 'canal_upsert'; result.needs_db = true;
    }

  } else if (sub === 'enable') {
    const cid = esc(args[0]);
    if (!cid) { result.reply_text = '❌ Uso: `/canal enable <channel_id>`'; result.format = 'static'; }
    else {
      result.sql = `UPDATE canais_descobertos SET ativo=true, updated_at=NOW() WHERE canal_id='${cid}' RETURNING canal_id, nome_canal, ativo;`;
      result.format = 'canal_upsert'; result.needs_db = true;
    }

  } else if (sub === 'disable') {
    const cid = esc(args[0]);
    if (!cid) { result.reply_text = '❌ Uso: `/canal disable <channel_id>`'; result.format = 'static'; }
    else {
      result.sql = `UPDATE canais_descobertos SET ativo=false, updated_at=NOW() WHERE canal_id='${cid}' RETURNING canal_id, nome_canal, ativo;`;
      result.format = 'canal_upsert'; result.needs_db = true;
    }

  } else {
    result.reply_text = '❓ Uso: `/canal list|add|enable|disable`';
    result.format = 'static';
  }

// ── /video ────────────────────────────────────────────────────────────────
} else if (cmd === 'video') {
  if (sub === 'list') {
    const validStatus = ['pendente','em_processamento','concluido','erro','ignorado'];
    const status = validStatus.includes(args[0]) ? args[0] : 'pendente';
    const limit = safeInt(args[1], 10, 50);
    result.sql = `SELECT video_id, canal_id,
  LEFT(titulo_original,45) as titulo,
  nicho, status,
  duracao_segundos,
  views,
  created_at::date as data
FROM videos_pendentes
WHERE status='${status}'
ORDER BY created_at DESC
LIMIT ${limit};`;
    result.format = 'video_list'; result.needs_db = true;

  } else if (sub === 'reprocessar') {
    const vid = esc(args[0]);
    if (!vid) { result.reply_text = '❌ Uso: `/video reprocessar <video_id>`'; result.format = 'static'; }
    else {
      result.sql = `UPDATE videos_pendentes
SET status='pendente', vizard_project_id=NULL, vizard_code=NULL, erro_msg=NULL, updated_at=NOW()
WHERE video_id='${vid}' OR id::text='${vid}'
RETURNING video_id, titulo_original, status;`;
      result.format = 'video_reprocess'; result.needs_db = true;
    }

  } else {
    result.reply_text = '❓ Uso: `/video list [status] [limit]` ou `/video reprocessar <video_id>`';
    result.format = 'static';
  }

// ── /status ───────────────────────────────────────────────────────────────
} else if (cmd === 'status') {
  result.sql = `SELECT
  (SELECT COUNT(*) FROM nichos WHERE ativo=true)::int           AS nichos_ativos,
  (SELECT COUNT(*) FROM canais_descobertos WHERE ativo=true)::int AS canais_ativos,
  (SELECT COUNT(*) FROM videos_pendentes WHERE status='pendente')::int       AS videos_pendentes,
  (SELECT COUNT(*) FROM videos_pendentes WHERE status='em_processamento')::int AS videos_processando,
  (SELECT COUNT(*) FROM videos_pendentes WHERE status='erro')::int           AS videos_erro,
  (SELECT COUNT(*) FROM clips_gerados WHERE status_publicacao='pronto_para_publicar')::int AS clips_prontos,
  (SELECT COUNT(*) FROM publicacoes WHERE data_publicacao::date=CURRENT_DATE AND status='publicado')::int AS publicados_hoje;`;
  result.format = 'status_overview'; result.needs_db = true;

// ── /clips ────────────────────────────────────────────────────────────────
} else if (cmd === 'clips') {
  const nicho = args[0] ? `AND cg.nicho='${esc(args[0])}'` : '';
  result.sql = `SELECT cg.titulo_final, cg.nicho, cg.duracao_clip, cg.score_clip
FROM clips_gerados cg
WHERE cg.status_publicacao='pronto_para_publicar' ${nicho}
ORDER BY cg.nicho, cg.score_clip DESC NULLS LAST
LIMIT 20;`;
  result.format = 'clips_list'; result.needs_db = true;

} else {
