    const cid = esc(args[0]);
    if (!cid) { result.reply_text = '❌ Uso: `/canal disable <channel_id>`'; result.format = 'static'; }
    else {
      result.sql = `UPDATE canais_descobertos SET ativo=false, updated_at=NOW() WHERE canal_id='${cid}' RETURNING canal_id, nome_canal, ativo;`;
      result.format = 'canal_upsert'; result.needs_db = true;
    }

  } else {
    result.reply_text = '❓ Uso: `/canal list|add|enable|disable`';
    result.format = 'static';
  }

// ── /video ────────────────────────────────────────────────────────────────
} else if (cmd === 'video') {
  if (sub === 'list') {
    const validStatus = ['pendente','em_processamento','concluido','erro','ignorado'];
    const status = validStatus.includes(args[0]) ? args[0] : 'pendente';
    const limit = safeInt(args[1], 10, 50);
    result.sql = `SELECT video_id, canal_id,
  LEFT(titulo_original,45) as titulo,
  nicho, status,
  duracao_segundos,
  views,
  created_at::date as data
FROM videos_pendentes
WHERE status='${status}'
ORDER BY created_at DESC
LIMIT ${limit};`;
    result.format = 'video_list'; result.needs_db = true;

  } else if (sub === 'reprocessar') {
    const vid = esc(args[0]);
    if (!vid) { result.reply_text = '❌ Uso: `/video reprocessar <video_id>`'; result.format = 'static'; }
    else {
      result.sql = `UPDATE videos_pendentes
SET status='pendente', vizard_project_id=NULL, vizard_code=NULL, erro_msg=NULL, updated_at=NOW()
WHERE video_id='${vid}' OR id::text='${vid}'
RETURNING video_id, titulo_original, status;`;
      result.format = 'video_reprocess'; result.needs_db = true;
    }

  } else {
    result.reply_text = '❓ Uso: `/video list [status] [limit]` ou `/video reprocessar <video_id>`';
    result.format = 'static';
  }

// ── /status ───────────────────────────────────────────────────────────────
} else if (cmd === 'status') {
  result.sql = `SELECT
  (SELECT COUNT(*) FROM nichos WHERE ativo=true)::int           AS nichos_ativos,
  (SELECT COUNT(*) FROM canais_descobertos WHERE ativo=true)::int AS canais_ativos,
  (SELECT COUNT(*) FROM videos_pendentes WHERE status='pendente')::int       AS videos_pendentes,
  (SELECT COUNT(*) FROM videos_pendentes WHERE status='em_processamento')::int AS videos_processando,
  (SELECT COUNT(*) FROM videos_pendentes WHERE status='erro')::int           AS videos_erro,
  (SELECT COUNT(*) FROM clips_gerados WHERE status_publicacao='pronto_para_publicar')::int AS clips_prontos,
  (SELECT COUNT(*) FROM publicacoes WHERE data_publicacao::date=CURRENT_DATE AND status='publicado')::int AS publicados_hoje;`;
  result.format = 'status_overview'; result.needs_db = true;

// ── /clips ────────────────────────────────────────────────────────────────
} else if (cmd === 'clips') {
  const nicho = args[0] ? `AND cg.nicho='${esc(args[0])}'` : '';
  result.sql = `SELECT cg.titulo_final, cg.nicho, cg.duracao_clip, cg.score_clip
FROM clips_gerados cg
WHERE cg.status_publicacao='pronto_para_publicar' ${nicho}
ORDER BY cg.nicho, cg.score_clip DESC NULLS LAST
LIMIT 20;`;
  result.format = 'clips_list'; result.needs_db = true;

} else {
  result.reply_text = `❓ Comando desconhecido: \`/${cmd}\`. Use \`/ajuda\` para ajuda.`;
  result.format = 'static';
}

return [{ json: result }];

