const data = $('parse-command').item.json;
const rows = $input.all().map(i => i.json);
const fmt = data.format;
let lines = [];

if (fmt === 'nicho_list') {
  lines.push('📋 *Nichos cadastrados:*\n');
  if (!rows.length || !rows[0].slug) { lines.push('_Nenhum nicho cadastrado._'); }
  else rows.forEach(r => {
    const st = r.ativo ? '✅' : '❌';
    lines.push(`${st} \`${r.slug}\` — ${r.nome} (${r.num_keywords || 0} kws)`);
  });

} else if (fmt === 'nicho_upsert') {
  if (!rows.length || !rows[0].slug) lines.push('⚠️ Nenhum registro afetado. Verifique o slug informado.');
  else {
    const r = rows[0];
    const st = r.ativo === false ? '❌ desativado' : r.ativo === true ? '✅ ativo' : '✅ atualizado';
    lines.push(`${st}: \`${r.slug || r.canal_id}\` — ${r.nome || r.nome_canal || ''}`);
  }

} else if (fmt === 'canal_list') {
  lines.push('📡 *Canais:*\n');
  if (!rows.length || !rows[0].canal_id) lines.push('_Nenhum canal encontrado._');
  else rows.forEach(r => {
    const st = r.ativo ? '✅' : '❌';
    const subs = r.inscritos >= 1000000 ? `${(r.inscritos/1000000).toFixed(1)}M`
               : r.inscritos >= 1000 ? `${Math.round(r.inscritos/1000)}k` : String(r.inscritos || '?');
    lines.push(`${st} \`${r.canal_id}\` — ${r.nome_canal} | ${r.nicho_alvo} | ${subs} | Score: ${r.score}`);
  });

} else if (fmt === 'canal_upsert') {
  if (!rows.length || !rows[0].canal_id) lines.push('⚠️ Nenhum canal afetado. Verifique o channel_id informado.');
  else {
    const r = rows[0];
    const st = r.ativo === false ? '❌ desativado' : '✅ ativo';
    lines.push(`${st}: \`${r.canal_id}\` — ${r.nome_canal}`);
  }

} else if (fmt === 'video_list') {
  lines.push(`🎬 *Vídeos* (${rows.filter(r=>r.video_id).length}):\n`);
  if (!rows.length || !rows[0].video_id) lines.push('_Nenhum vídeo encontrado._');
  else rows.forEach(r => {
    const dur = r.duracao_segundos ? `${Math.floor(r.duracao_segundos/60)}m${r.duracao_segundos%60}s` : '?';
    const views = (r.views||0) >= 1000 ? `${Math.round((r.views||0)/1000)}k` : String(r.views||0);
    lines.push(`• \`${r.video_id}\` ${r.titulo || '?'} | ${dur} | ${views} views | ${r.nicho}`);
  });

} else if (fmt === 'video_reprocess') {
  if (!rows.length || !rows[0].video_id) lines.push('⚠️ Vídeo não encontrado.');
  else {
    const r = rows[0];
    lines.push(`♻️ Reprocessando: \`${r.video_id}\`\n${r.titulo_original?.substring(0,50) || ''}\nStatus → \`${r.status}\``);
  }

} else if (fmt === 'status_overview') {
  const r = rows[0] || {};
  lines.push('📊 *Status da Pipeline*\n');
  lines.push(`🏷️ Nichos ativos:      *${r.nichos_ativos || 0}*`);
  lines.push(`📡 Canais ativos:      *${r.canais_ativos || 0}*`);
  lines.push(`⏳ Vídeos pendentes:   *${r.videos_pendentes || 0}*`);
  lines.push(`⚙️ Em processamento:  *${r.videos_processando || 0}*`);
  lines.push(`❌ Com erro:           *${r.videos_erro || 0}*`);
  lines.push(`✂️ Clips prontos:      *${r.clips_prontos || 0}*`);
  lines.push(`📤 Publicados hoje:    *${r.publicados_hoje || 0}*`);

} else if (fmt === 'clips_list') {
  lines.push(`✂️ *Clips prontos* (${rows.filter(r=>r.titulo_final).length}):\n`);
  if (!rows.length || !rows[0].titulo_final) lines.push('_Nenhum clip pronto._');
  else rows.forEach(r => {
    const dur = r.duracao_clip ? `${Math.floor(r.duracao_clip/60)}m${r.duracao_clip%60}s` : '?';
    lines.push(`• ${r.titulo_final?.substring(0,45)} | ${r.nicho} | ${dur} | Score: ${r.score_clip||0}`);
  });

} else {
  lines.push('✅ Ok!');
}

return [{ json: {
  chat_id: data.chat_id,
  text: lines.join('\n'),
  parse_mode: 'Markdown'
} }];

